#include <stdio.h>
#include <stdlib.h>

typedef struct {int val; int cnt;} Pair;

int cmp(const void *a, const void *b) {
    const Pair *x = (const Pair *)a;
    const Pair *y = (const Pair *)b;
    if (x->cnt != y->cnt) return x->cnt - y->cnt;
    return x->val - y->val;
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n; scanf("%d", &n);
        int freq[101] = {0};
        for (int i = 0; i < n; ++i) {
            int x; scanf("%d", &x);
            freq[x]++;
        }
        Pair arr[101];
        int m = 0;
        for (int v = 1; v <= 100; ++v) if (freq[v]) { arr[m].val = v; arr[m].cnt = freq[v]; ++m; }
        qsort(arr, m, sizeof(Pair), cmp);
        int first = 1;
        for (int i = 0; i < m; ++i) {
            for (int j = 0; j < arr[i].cnt; ++j) {
                if (!first) printf(" ");
                printf("%d", arr[i].val);
                first = 0;
            }
        }
        printf("\n");
    }
    return 0;
}

