const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
const T = Number(input[idx++]);
let outputs = [];
for (let t = 0; t < T; t++) {
  const n = Number(input[idx++]);
  const freq = new Array(101).fill(0);
  for (let i = 0; i < n; i++) {
    const x = Number(input[idx++]);
    freq[x]++;
  }
  const pairs = [];
  for (let v = 1; v <= 100; v++) if (freq[v]) pairs.push([v, freq[v]]);
  pairs.sort((a, b) => a[1] !== b[1] ? a[1] - b[1] : a[0] - b[0]);
  const line = [];
  for (const [val, cnt] of pairs) {
    for (let i = 0; i < cnt; i++) line.push(String(val));
  }
  outputs.push(line.join(' '));
}
console.log(outputs.join('\n'));
